#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 4e5+5;
struct line{int x,y;}ln[N];
struct Three{int x,y,z;};
int n,m,k,fa[N],sz[N],dis[N];
vector<int> g[N],s[N];
int min(int x,int y){return (x<y?x:y);}
int max(int x,int y){return (x>y?x:y);}
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int ls(int u){return (u<<1);}int rs(int u){return (u<<1|1);}
void Addition(int u,int l,int r,int L,int R,int x){
    if(L<=l&&r<=R){s[u].pb(x);return;}int mid=(l+r)>>1;
    if(L<=mid)Addition(ls(u),l,mid,L,R,x);
    if(R>mid)Addition(rs(u),mid+1,r,L,R,x);return;
}
int FF(int u){return (fa[u]==u?u:FF(fa[u]));}
void Solve(int u,int l,int r,bool flag){
    stack<Three> st;
    for(auto tmp:s[u]){
        auto [x,y]=ln[tmp];
        int Fx=FF(x),Fy=FF(y);
        if(Fx==Fy)continue;
        if(dis[Fx]<dis[Fy])swap(x,y),swap(Fx,Fy);
        st.push({Fy,(dis[Fx]==dis[Fy]),sz[Fy]});
        fa[Fy]=Fx,dis[Fx]+=(dis[Fx]==dis[Fy]),sz[Fx]+=sz[Fy];
        if(sz[Fx]==n)flag=1;
    }
    if(l==r)cout<<(flag?"Connected\n":"Disconnected\n");
    else{int mid=(l+r)>>1;Solve(ls(u),l,mid,flag);Solve(rs(u),mid+1,r,flag);}
    while(!st.empty()){
        auto [x,y,z]=st.top();st.pop();
        dis[fa[x]]-=y,sz[fa[x]]-=z,fa[x]=x;
    }
    return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++)ln[i].x=read(),ln[i].y=read();
    k=read();for(int i=1;i<=m;i++)g[i].pb(0);
    for(int i=1;i<=k;i++)for(int j=read();j;j--)g[read()].pb(i);
    for(int i=1;i<=m;i++)g[i].pb(k+1);
    for(int i=1;i<=m;i++)for(int j=1;j<g[i].size();j++)
        if(g[i][j-1]+1<=g[i][j]-1)Addition(1,1,k,g[i][j-1]+1,g[i][j]-1,i);
    for(int i=1;i<=n;i++)fa[i]=i,sz[i]=1,dis[i]=1;Solve(1,1,k,0);
    return 0;
}
